 84 |     override fun onKeyEvent(event: KeyEvent): Boolean {
 85 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 86 |         // Absolute first check - if inactive, pass through immediately
 87 |         if (!prefs.getBoolean("is_active", true)) return false
 88 | 
 89 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
 90 |         val isScreenOn = pm.isInteractive
 91 |         if (!prefs.getBoolean("keys_enabled", true)) return false
 92 | 
 93 |         val keyCode = event.keyCode
 94 |         val action = event.action
 95 |         val isLongPress = (event.eventTime - event.downTime) > 600
 96 | 
 97 |         // 1. Camera Context & Emergency Logic
 98 |         val root = rootInActiveWindow
 99 |         val pkg = root?.packageName?.toString() ?: ""
100 |         val isCamOpen = pkg.contains("camera") || pkg.contains("lens")
101 | 
102 |         if (isCamOpen && (keyCode == KeyEvent.KEYCODE_VOLUME_UP || keyCode == KeyEvent.KEYCODE_VOLUME_DOWN)) {
103 |             // --- Emergency Blocker Removal (Priority 1) ---
104 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP && action == KeyEvent.ACTION_UP) {
105 |                 val now = System.currentTimeMillis()
106 |                 if (now - lastUpTime < 400 && blockerOverlay != null) {
107 |                     DebugLogger.log("BLOCKER", "Emergency Removal via VolUp Double-Tap")
108 |                     removeTouchBlocker()
109 |                     return true // Consume to prevent shutter on emergency exit
110 |                 }
111 |                 lastUpTime = now
112 |                 // Fall through to check for shutter action
113 |             }
114 | 
115 |             // --- Shutter Trigger (Priority 2) ---
116 |             if (action == KeyEvent.ACTION_UP) {
117 |                 DebugLogger.log("SHUTTER", "Camera context: Intercepting volume key for capture.")
118 |                 smartShutterClick()
119 |                 return true // Consume the event so the native camera doesn't also fire.
120 |             }
121 | 
122 |             // For ACTION_DOWN or other events, pass them through to allow native camera functions like focus.
123 |             return false
124 |         }
125 | 
126 |         // 2. Headset Hijack Logic (Highest Priority)
127 |         val isHeadsetKey = keyCode == KeyEvent.KEYCODE_HEADSETHOOK || 
128 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PLAY_PAUSE || 
129 |                           keyCode == KeyEvent.KEYCODE_MEDIA_NEXT || 
130 |                           keyCode == KeyEvent.KEYCODE_MEDIA_PREVIOUS
131 | 
132 |         if (isHeadsetKey) {
133 |             if (action == KeyEvent.ACTION_DOWN) {
134 |                 if (event.repeatCount == 0) {
135 |                     lastHeadsetDownTime = event.eventTime
136 |                     val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
137 |                     val wl = pm.newWakeLock(PowerManager.PARTIAL_WAKE_LOCK, "UniversalApp::KeyHijack")
138 |                     wl.acquire(500)
139 |                 }
140 |                 return true 
141 |             }
142 |             if (action == KeyEvent.ACTION_UP) {
143 |                 val duration = event.eventTime - lastHeadsetDownTime
144 |                 val type = if (duration > 600) "L" else "S"
145 |                 DebugLogger.log("HEADSET_RAW", "Press: ${duration}ms -> Added: $type")
146 |                 handler.removeCallbacks(headsetGestureRunnable)
147 |                 
148 |                 gestureSequence += type
149 |                 
150 |                 handler.postDelayed(headsetGestureRunnable, 450)
151 |                 return true
152 |             }
153 |         }
154 | 
155 |         // 3. Volume Key DOWN Logic
156 |         if (action == KeyEvent.ACTION_DOWN) {
157 |             val now = System.currentTimeMillis()
158 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) {
159 |                 isVolUpPressed = true
160 |                 isWaitingForTapHold = (now - lastUpTime < 800)
161 |             }
162 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) {
163 |                 isVolDownPressed = true
164 |                 isWaitingForDownTapHold = (now - lastDownTime < 800)
165 |             }
166 | 
167 |             if (event.repeatCount > 0) return true
168 |             if (isVolUpPressed && isVolDownPressed) return true
169 | 
170 |             when (keyCode) {
171 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
172 |                     if (event.repeatCount == 0) {
173 |                         isLongPressTriggered = false
174 |                         handler.postDelayed(volUpLongPressRunnable, 5000)
175 |                     }
176 |                     val now = System.currentTimeMillis()
177 |                     if (now - lastUpTime < CLICK_GAP) upCount++ else upCount = 1
178 |                     lastUpTime = now
179 |                     return true
180 |                 }
181 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
182 |                     if (event.repeatCount == 0) {
183 |                         isLongPressTriggered = false
184 |                         handler.postDelayed(volDownBatchRunnable, 5000)
185 |                     }
186 |                     val now = System.currentTimeMillis()
187 |                     if (now - lastDownTime < CLICK_GAP) downCount++ else downCount = 1
188 |                     lastDownTime = now
189 |                     return true
190 |                 }
191 |             }
192 |         }
193 | 
194 |         // 4. Volume Key UP Logic
195 |         if (action == KeyEvent.ACTION_UP) {
196 |             val wasBothPressed = isVolUpPressed && isVolDownPressed
197 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_UP) isVolUpPressed = false
198 |             if (keyCode == KeyEvent.KEYCODE_VOLUME_DOWN) isVolDownPressed = false
199 | 
200 |             if (wasBothPressed) {
201 |                 val intent = Intent(this, PlaybackService::class.java)
202 |                 intent.action = if (isLongPress) "RESET" else "PAUSE"
203 |                 startService(intent)
204 |                 return true
205 |             }
206 | 
207 | 
208 | 
209 |             when (keyCode) {
210 |                 KeyEvent.KEYCODE_VOLUME_UP -> {
211 |                     handler.removeCallbacks(volUpLongPressRunnable)
212 |                     if (isLongPressTriggered) {
213 |                         isLongPressTriggered = false
214 |                         upCount = 0
215 |                         isWaitingForTapHold = false
216 |                         return true
217 |                     }
218 |                     
219 |                     val duration = event.eventTime - event.downTime
220 |                     if (isWaitingForTapHold && duration > 500) {
221 |                         toggleCamera()
222 |                         isWaitingForTapHold = false
223 |                         upCount = 0 
224 |                         return true 
225 |                     }
226 |                     isWaitingForTapHold = false
227 |                     handlePress("UP", upCount, isLongPress)
228 |                 }
229 |                 KeyEvent.KEYCODE_VOLUME_DOWN -> {
230 |                     handler.removeCallbacks(volDownBatchRunnable)
231 |                     if (isLongPressTriggered) return true
232 |                     
233 |                     val duration = event.eventTime - event.downTime
234 |                     if (isWaitingForDownTapHold && duration > 500) {
235 |                         triggerReset()
236 |                         isWaitingForDownTapHold = false
237 |                         downCount = 0
238 |                         return true
239 |                     }
240 |                     isWaitingForDownTapHold = false
241 |                     handlePress("DOWN", downCount, isLongPress)
242 |                 }
243 |             }
244 |             return true
245 |         }
246 | 
247 |         return super.onKeyEvent(event)
248 |     }
