252 |         val currentPackage = root?.packageName?.toString() ?: ""
253 |         
254 |         if (currentPackage.contains("camera") || currentPackage.contains("lens") || currentPackage.contains("capture")) {
255 |             DebugLogger.log("CAM_TOGGLE", "Camera detected active. Closing.")
256 |             isInCameraSession = false // Mark inactive to prevent double-speech in AccessibilityEvent
257 |             autoCaptureRunnable?.let { handler.removeCallbacks(it) }
