359 |     private fun prepareWideLens(): Boolean {
360 |         val root = rootInActiveWindow ?: return false
361 |         
362 |         var lensNode: AccessibilityNodeInfo? = null
363 |         val searchTerms = listOf(".5", "0.5", "0,5", "0.6", "0.5x", "0,5x", "ultra", "wide", "zoom out")
364 |         val bounds = Rect()
365 | 
366 |         val queue = LinkedList<AccessibilityNodeInfo>()
367 |         queue.add(root)
368 |         while (!queue.isEmpty()) {
369 |             val node = queue.poll() ?: continue
370 |             val text = node.text?.toString()?.lowercase() ?: ""
371 |             val desc = node.contentDescription?.toString()?.lowercase() ?: ""
372 |             
373 |             val match = searchTerms.find { (text.contains(it) || desc.contains(it)) && !text.contains("1x") }
374 | 
375 |             if (match != null) {
376 |                 var current: AccessibilityNodeInfo? = node
377 |                 var depth = 0
378 |                 while (current != null && depth < 6) {
379 |                     if (current.isClickable) {
380 |                         lensNode = current
381 |                         break
382 |                     }
383 |                     current = current.parent
384 |                     depth++
385 |                 }
386 |                 if (lensNode != null) break
387 |             }
388 |             for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
389 |         }
390 | 
391 |         return if (lensNode != null) {
392 |             // Try Virtual Click first (Robust Verification)
393 |             val success = lensNode.performAction(AccessibilityNodeInfo.ACTION_CLICK)
394 |             
395 |             if (success) {
396 |                 DebugLogger.log("LENS_FLOW", "Virtual click SUCCESS")
397 |                 speak("Wide lens activated", true)
398 |                 true
399 |             } else {
400 |                 // Fallback to Physical Tap for Samsung/Google Camera
401 |                 lensNode.getBoundsInScreen(bounds)
402 |                 val x = bounds.centerX().toFloat()
403 |                 val y = bounds.centerY().toFloat()
404 |                 
405 |                 val clickPath = Path().apply { moveTo(x, y) }
406 |                 val gesture = GestureDescription.Builder()
407 |                     .addStroke(GestureDescription.StrokeDescription(clickPath, 0, 50))
408 |                     .build()
409 |                 
410 |                 dispatchGesture(gesture, null, null)
411 |                 DebugLogger.log("LENS_FLOW", "Virtual click REJECTED. Physical tap dispatched to $x, $y")
412 |                 // Return false so the retry loop continues to verify the switch
413 |                 false
414 |             }
415 |         } else {
416 |             false
417 |         }
418 |     }
