460 |     private fun performPinchFallback() {
461 |         val metrics = resources.displayMetrics
462 |         val centerX = metrics.widthPixels / 2f
463 |         val centerY = metrics.heightPixels / 2f
464 |         val path1 = android.graphics.Path().apply { moveTo(100f, 100f); lineTo(centerX - 50, centerY - 50) }
465 |         val path2 = android.graphics.Path().apply { moveTo(metrics.widthPixels - 100f, 100f); lineTo(centerX + 50, centerY - 50) }
466 |         val stroke1 = GestureDescription.StrokeDescription(path1, 0, 500)
467 |         val stroke2 = GestureDescription.StrokeDescription(path2, 0, 500)
468 |         val gesture = GestureDescription.Builder().addStroke(stroke1).addStroke(stroke2).build()
