470 |         dispatchGesture(gesture, object : AccessibilityService.GestureResultCallback() {
471 |             override fun onCompleted(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch SUCCESS")
472 |             override fun onCancelled(gestureDescription: GestureDescription) = DebugLogger.log("GESTURE", "Pinch FAILED")
473 |         }, null)
