476 |     private fun smartShutterClick() {
477 |         // Cancel any pending auto-shutter if manual shutter or auto-loop is triggered
478 |         autoCaptureRunnable?.let { handler.removeCallbacks(it) }
479 |         autoCaptureRunnable = null
480 | 
481 |         val root = rootInActiveWindow
482 |         val pkg = root?.packageName?.toString() ?: ""
483 |         val isCamera = pkg.contains("camera") || pkg.contains("lens")
484 | 
485 |         if (!isCamera) {
486 |             DebugLogger.log("SHUTTER", "Blocked: Camera not in foreground ($pkg)")
487 |             // Only speak if this wasn't an automatic attempt
488 |             if (successiveRemaining == 0) speak("Camera is not launched yet", true)
489 |             return
490 |         }
491 | 
492 |         // --- Successive Capture Logic ---
493 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
494 |         val isSuccessive = prefs.getBoolean("successive_enabled", false)
495 |         if (isSuccessive && successiveRemaining == 0) {
496 |             successiveRemaining = prefs.getInt("successive_count", 3) - 1
497 |             triggerSuccessiveLoop()
498 |         }
499 | 
500 |         var foundNode: AccessibilityNodeInfo? = null
501 |         if (root != null) {
502 |             val targets = listOf("shutter", "take picture", "capture", "camera_shutter", "bottom_bar_shutter")
503 |             val queue = LinkedList<AccessibilityNodeInfo>()
504 |             queue.add(root)
505 |             
506 |             while (!queue.isEmpty()) {
507 |                 val node = queue.poll() ?: continue
508 |                 val id = node.viewIdResourceName?.lowercase() ?: ""
509 |                 val desc = node.contentDescription?.toString()?.lowercase() ?: ""
510 |                 
511 |                 if (targets.any { id.contains(it) || desc.contains(it) } && node.isClickable) {
512 |                     foundNode = node
513 |                     break
514 |                 }
515 |                 for (i in 0 until node.childCount) { node.getChild(i)?.let { queue.add(it) } }
516 |             }
517 |         }
518 | 
519 |         if (foundNode != null) {
520 |             DebugLogger.log("AUTO", "Smart Shutter Active")
521 |             if (successiveRemaining <= 0) speak("Capturing image")
522 |             foundNode.performAction(android.view.accessibility.AccessibilityNodeInfo.ACTION_CLICK)
523 |         } else {
524 |             DebugLogger.log("AUTO", "Shutter Node Missing")
525 |             if (successiveRemaining <= 0) speak("Shutter not visible, using fallback")
526 |             clickShutterCoordinates()
527 |         }
528 |     }
