539 |             val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
540 |             val total = prefs.getInt("successive_count", 3)
541 |             DebugLogger.log("AUTO", "Batch complete. Closing camera automatically.")
542 |             speak("Batch complete. Closing camera.", true)
