599 |     private fun processHeadsetGesture(sequence: String) {
600 |         if (sequence.isEmpty()) return
601 |         DebugLogger.log("HEADSET_SIG", "Evaluating sequence: '$sequence' | NavMode: $isEarphoneNavMode")
602 |         val intent = Intent(this, PlaybackService::class.java)
603 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
604 |         
605 |         val root = rootInActiveWindow
606 |         val pkg = root?.packageName?.toString() ?: ""
607 |         val isCam = pkg.contains("camera") || pkg.contains("lens")
608 | 
609 |         // --- GLOBAL PRIORITY COMMANDS ---
610 | 
611 |         // 1. Wake (Screen Off + Single Click)
612 |         if (!pm.isInteractive && sequence == "S") {
613 |             wakeDevice(pm)
614 |             return
615 |         }
616 | 
617 |         // 2. Global Lock (Triple Click ALWAYS locks screen)
618 |         if (sequence == "SSS") {
619 |             DebugLogger.log("HEADSET", "Global Lock Triggered")
620 |             if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.P) {
621 |                 performGlobalAction(AccessibilityService.GLOBAL_ACTION_LOCK_SCREEN)
622 |             } else {
623 |                 speak("Lock feature requires Android 9", true)
624 |             }
625 |             return
626 |         }
627 | 
628 |         // 3. Global Reset (Long-Short ALWAYS clears session)
629 |         if (sequence == "LS") {
630 |             DebugLogger.log("HEADSET", "Global Session Reset Triggered")
631 |             val resetIntent = Intent(this, PlaybackService::class.java).apply { action = "RESET" }
632 |             startService(resetIntent)
633 |             return
634 |         }
635 | 
