 400 |     private fun processNextInQueue() {
 401 |         if (synthesisQueue.isEmpty()) return
 402 |         val (text, file) = synthesisQueue.poll() ?: return
 403 |         val utteranceId = file.name
 404 |         
 405 |         val params = Bundle().apply { putString(TextToSpeech.Engine.KEY_PARAM_UTTERANCE_ID, utteranceId) }
 406 |         val result = tts.synthesizeToFile(text, params, file, utteranceId)
 407 |         if (result == TextToSpeech.ERROR) {
 408 |             DebugLogger.log("TTS_ERR", "Engine rejected: $utteranceId")
 409 |             if (pendingSyntheses.decrementAndGet() <= 0) finalizeBatch() else processNextInQueue()
 410 |         }
 411 |     }
