 435 |         stopAllPlayback()
 436 |         val list = playlists[type]
 437 |         
 438 |         val readableType = when(type) {
 439 |             "wo" -> "worked out solutions"
 440 |             "tf" -> "true or false"
 441 |             "sa" -> "short answers"
 442 |             "mc" -> "multiple choice"
 443 |             "ma" -> "matching"
 444 |             "fill" -> "fill in the blanks"
 445 |             else -> "solutions"
 446 |         }
