 448 |         if (list.isNullOrEmpty()) {
 449 |             speakStatus("$readableType not available", 2)
 450 |             return
 451 |         }
 452 | 
 453 |         speakStatus("Playing $readableType", 2)
 454 |         currentType = type
 455 |         currentIndex = 0
 456 |         savePlaybackState()
 457 |         // Add delay to let TTS finish announcement before starting file
 458 |         handler.postDelayed({ playCurrent() }, 1500)
 459 |     }
