 461 |     private fun playNext() {
 462 |         val type = currentType
 463 |         val list = playlists[type]
 464 | 
 465 |         if (type == null || list.isNullOrEmpty()) {
 466 |             speakStatus("No solutions loaded", 2)
 467 |             return
 468 |         }
 469 |         
 470 |         stopMediaOnly()
 471 | 
 472 |         if (currentIndex >= list.size - 1) {
 473 |             // End of category reached: Advance to next category automatically
 474 |             DebugLogger.log("NAV", "End of $type reached. Advancing to next category.")
 475 |             playNextCategory()
 476 |         } else {
 477 |             currentIndex++
 478 |             speakStatus("Next solution", 2)
 479 |             DebugLogger.log("NAV", "Next: Index $currentIndex of ${list.size}")
 480 |             savePlaybackState()
 481 |             handler.postDelayed({ playCurrent() }, 1500)
 482 |         }
 483 |     }
