 487 |         stopMediaOnly()
 488 | 
 489 |         if (types.isEmpty()) {
 490 |             speakStatus("No data loaded", 2)
 491 |             return
 492 |         }
 493 |         
 494 |         if (types.size <= 1) {
 495 |             speakStatus("No other categories found", 2)
 496 |             handler.postDelayed({ playCurrent() }, 1500)
 497 |             return
 498 |         }
