 533 |     private fun playCurrent() {
 534 |         val list = playlists[currentType] ?: return
 535 |         if (currentIndex < 0 || currentIndex >= list.size) currentIndex = 0
 536 |         val file = list[currentIndex]
 537 | 
 538 |         // --- STEALTH CHECK ---
 539 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 540 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 541 |         if (prefs.getBoolean("headset_only", true) && !am.isWiredHeadsetOn && !am.isBluetoothA2dpOn) {
 542 |             DebugLogger.log("STEALTH", "Playback blocked: Stealth mode active and no headset found.")
 543 |             return
 544 |         }
 545 | 
 546 |         DebugLogger.log("MEDIA_TRACE", "Attempting playback of ${file.name} (Size: ${file.length()} bytes)")
 547 | 
 548 |         // ANTI-LOOP GUARD: If file is missing or empty, do not play.
 549 |         // Increased to 1KB to ensure a valid audio header exists.
 550 |         if (!file.exists() || file.length() < 1024) {
 551 |             DebugLogger.log("MEDIA_ERR", "ABORT: File ${file.name} size is ${file.length()} bytes. (Min 1024 required)")
 552 |             speakStatus("Audio file is still being generated. Please try again in a moment.", 2)
 553 |             return
 554 |         }
 555 | 
 556 |         try {
 557 |             if (mediaPlayer == null) {
 558 |                 mediaPlayer = MediaPlayer().apply {
 559 |                     setDataSource(file.absolutePath)
 560 |                     setAudioAttributes(android.media.AudioAttributes.Builder()
 561 |                         .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 562 |                         .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 563 |                         .build())
 564 |                     prepareAsync()
 565 |                     setOnPreparedListener { 
 566 |                         DebugLogger.log("MEDIA", "Starting Playback: ${file.name}")
 567 |                         start() 
 568 |                     }
 569 |                     setOnErrorListener { _, what, extra ->
 570 |                         DebugLogger.log("MEDIA_ERR", "MediaPlayer Error: $what / $extra")
 571 |                         stopAllPlayback()
 572 |                         true
 573 |                     }
 574 |                     setOnCompletionListener {
 575 |                         DebugLogger.log("MEDIA", "Playback finished for ${file.name}")
 576 |                         // Mandatory delay to prevent rapid-fire loops
 577 |                         handler.postDelayed({ playNext() }, 1000)
 578 |                     }
 579 |                 }
 580 |             }
 581 |         } catch (e: Exception) { 
 582 |             DebugLogger.log("MEDIA_CRITICAL", "Failed to init MediaPlayer: ${e.message}")
 583 |             stopAllPlayback()
 584 |         }
 585 |     }
