 587 |     private fun pauseAudio() {
 588 |         val list = playlists[currentType]
 589 |         if (list.isNullOrEmpty()) {
 590 |             speakStatus("No solutions loaded to play.", 2)
 591 |             return
 592 |         }
 593 |         
 594 |         if (mediaPlayer?.isPlaying == true) {
 595 |             mediaPlayer?.pause()
 596 |             speakStatus("Paused", 2)
 597 |             updateMediaSessionState(false)
 598 |         } else {
