 750 |     private var isClaiming = false
 751 |     private fun claimMediaFocus() {
 752 |         val now = System.currentTimeMillis()
 753 |         // Cooldown: Stop the OS focus-war loop (5-second minimum gap)
 754 |         if (isFocusHeld || isClaiming || (now - lastFocusLossTime < 5000)) return
 755 |         isClaiming = true
 756 | 
 757 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 758 |         
 759 |         if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
 760 |             val focusRequest = android.media.AudioFocusRequest.Builder(android.media.AudioManager.AUDIOFOCUS_GAIN)
 761 |                 .setAudioAttributes(android.media.AudioAttributes.Builder()
 762 |                     .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 763 |                     .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 764 |                     .build())
 765 |                 .setOnAudioFocusChangeListener { focusChange ->
 766 |                     when (focusChange) {
 767 |                         android.media.AudioManager.AUDIOFOCUS_LOSS,
 768 |                         android.media.AudioManager.AUDIOFOCUS_LOSS_TRANSIENT -> {
 769 |                             isFocusHeld = false
 770 |                             lastFocusLossTime = System.currentTimeMillis()
 771 |                             DebugLogger.log("SESSION", "Focus Surrendered")
 772 |                             handler.postDelayed({ isClaiming = false }, 5000)
 773 |                         }
 774 |                         android.media.AudioManager.AUDIOFOCUS_GAIN -> {
 775 |                             isFocusHeld = true
 776 |                             DebugLogger.log("SESSION", "Focus Re-Gained")
 777 |                         }
 778 |                     }
 779 |                 }
 780 |                 .build()
 781 |             
 782 |             val result = am.requestAudioFocus(focusRequest)
 783 |             if (result == android.media.AudioManager.AUDIOFOCUS_REQUEST_GRANTED) {
 784 |                 isFocusHeld = true
 785 |                 isClaiming = false
 786 |                 DebugLogger.log("SESSION", "Focus Secured")
 787 |                 mediaSession?.isActive = true
 788 |                 startSilentLoop()
 789 |             } else {
 790 |                 isClaiming = false
 791 |                 lastFocusLossTime = System.currentTimeMillis()
 792 |             }
 793 |         } else {
 794 |             isClaiming = false
 795 |         }
 796 |     }
