 842 |     private fun handleHeadsetCommand() {
 843 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
 844 |         val isScreenOff = !pm.isInteractive
 845 |         
 846 |         DebugLogger.log("HEADSET_EVENT", "--- HEADSET CLICK DETECTED ---")
