 866 |     private var wakeRetryCount = 0
 867 |     private fun wakeDevice(pm: PowerManager) {
 868 |         DebugLogger.log("WAKE_TRACE", "Step 1: Entering wakeDevice() function")
 869 |         
 870 |         if (pm.isInteractive) {
 871 |             DebugLogger.log("WAKE_TRACE", "Step 1.1: Cancelled - Device is already interactive")
 872 |             return
 873 |         }
 874 | 
 875 |         try {
 876 |             // 1. Prepare Intent
 877 |             DebugLogger.log("WAKE_TRACE", "Step 2: Building WakeActivity Intent")
 878 |             val intent = Intent(this, WakeActivity::class.java).apply {
 879 |                 addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or 
 880 |                          Intent.FLAG_ACTIVITY_CLEAR_TOP or 
 881 |                          Intent.FLAG_ACTIVITY_SINGLE_TOP)
 882 |             }
 883 |             
 884 |             val pendingIntent = PendingIntent.getActivity(
 885 |                 this, 
 886 |                 999, 
 887 |                 intent, 
 888 |                 PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
 889 |             )
 890 |             DebugLogger.log("WAKE_TRACE", "Step 3: PendingIntent created (ID: 999)")
 891 | 
 892 |             // 2. Build High-Priority Notification
 893 |             val builder = NotificationCompat.Builder(this, "PlaybackChannel")
 894 |                 .setSmallIcon(android.R.drawable.ic_lock_power_off)
 895 |                 .setContentTitle("System Wake Request")
 896 |                 .setContentText("Click to restore visual interface")
 897 |                 .setPriority(NotificationCompat.PRIORITY_MAX)
 898 |                 .setCategory(NotificationCompat.CATEGORY_ALARM)
 899 |                 .setFullScreenIntent(pendingIntent, true)
 900 |                 .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
 901 |                 .setVibrate(longArrayOf(0L)) // Mute system vibration (0ms)
 902 |                 .setAutoCancel(true)
 903 |             DebugLogger.log("WAKE_TRACE", "Step 4: Notification Builder configured with FullScreenIntent")
 904 | 
 905 |             val nm = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
 906 |             
 907 |             // 3. Physical Hardware Wake - Using FULL_WAKE_LOCK for maximum power
 908 |             @Suppress("DEPRECATION")
 909 |             val wl = pm.newWakeLock(PowerManager.FULL_WAKE_LOCK or PowerManager.ACQUIRE_CAUSES_WAKEUP or PowerManager.ON_AFTER_RELEASE, "UniversalApp::EmergencyWake")
 910 |             
 911 |             DebugLogger.log("WAKE_TRACE", "Step 5: WakeLock created. Attempting acquire(10s)...")
 912 |             wl.acquire(10000L)
 913 |             DebugLogger.log("WAKE_TRACE", "Step 6: WakeLock ACQUIRED")
 914 | 
 915 |             // 4. Fire Notification
 916 |             DebugLogger.log("WAKE_TRACE", "Step 7: Dispatching Notification to NotificationManager")
 917 |             nm.notify(99, builder.build())
 918 |             
 919 |             // 5. Fire Activity Directly
 920 |             DebugLogger.log("WAKE_TRACE", "Step 8: Calling startActivity(WakeActivity)")
 921 |             startActivity(intent)
 922 |             DebugLogger.log("WAKE_TRACE", "Step 9: startActivity command sent")
 923 | 
 924 |             verifyPhysicalWake(pm, 0)
 925 |             
 926 |             handler.postDelayed({
 927 |                 DebugLogger.log("WAKE_TRACE", "Step 10: Cleaning up Wake Notification")
 928 |                 nm.cancel(99)
 929 |             }, 5000)
 930 | 
 931 |         } catch (e: Exception) {
 932 |             DebugLogger.log("WAKE_CRITICAL", "CRASH in wake sequence: ${e.message}")
 933 |             e.printStackTrace()
 934 |         }
 935 |     }
