 937 |     private fun verifyPhysicalWake(pm: PowerManager, checkCount: Int) {
 938 |         handler.postDelayed({
 939 |             val logicallyOn = pm.isInteractive
 940 |             DebugLogger.log("WAKE_VERIFY", "Check #$checkCount: Interactive=$logicallyOn")
 941 | 
 942 |             if (logicallyOn) {
 943 |                 wakeRetryCount = 0
 944 |                 // Service stays silent; we wait for WakeActivity.onWindowFocusChanged
 945 |                 DebugLogger.log("WAKE_VERIFY", "Logical wake confirmed. Waiting for Activity Focus signal.")
 946 |             } else if (checkCount < 8) { // Increased checks for slower devices
 947 |                 verifyPhysicalWake(pm, checkCount + 1)
 948 |             } else {
