 529 |     private fun playCurrent() {
 530 |         val list = playlists[currentType] ?: return
 531 |         if (currentIndex < 0 || currentIndex >= list.size) currentIndex = 0
 532 |         val file = list[currentIndex]
 533 | 
 534 |         // --- STEALTH CHECK ---
 535 |         val prefs = getSharedPreferences("monitor_prefs", Context.MODE_PRIVATE)
 536 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 537 |         if (prefs.getBoolean("headset_only", true) && !am.isWiredHeadsetOn && !am.isBluetoothA2dpOn) {
 538 |             DebugLogger.log("STEALTH", "Playback blocked: Stealth mode active and no headset found.")
 539 |             return
 540 |         }
 541 | 
 542 |         DebugLogger.log("MEDIA_TRACE", "Attempting playback of ${file.name} (Size: ${file.length()} bytes)")
 543 | 
 544 |         // ANTI-LOOP GUARD: If file is missing or empty, do not play.
 545 |         // Increased to 1KB to ensure a valid audio header exists.
 546 |         if (!file.exists() || file.length() < 1024) {
 547 |             DebugLogger.log("MEDIA_ERR", "ABORT: File ${file.name} size is ${file.length()} bytes. (Min 1024 required)")
 548 |             speakStatus("Audio file is still being generated. Please try again in a moment.", 2)
 549 |             return
 550 |         }
 551 | 
 552 |         try {
 553 |             if (mediaPlayer == null) {
 554 |                 mediaPlayer = MediaPlayer().apply {
 555 |                     setDataSource(file.absolutePath)
 556 |                     setAudioAttributes(android.media.AudioAttributes.Builder()
 557 |                         .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 558 |                         .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 559 |                         .build())
 560 |                     prepareAsync()
 561 |                     setOnPreparedListener { 
 562 |                         DebugLogger.log("MEDIA", "Starting Playback: ${file.name}")
 563 |                         start() 
 564 |                     }
 565 |                     setOnErrorListener { _, what, extra ->
 566 |                         DebugLogger.log("MEDIA_ERR", "MediaPlayer Error: $what / $extra")
 567 |                         stopAllPlayback()
 568 |                         true
 569 |                     }
 570 |                     setOnCompletionListener {
 571 |                         DebugLogger.log("MEDIA", "Playback finished for ${file.name}")
 572 |                         // Mandatory delay to prevent rapid-fire loops
 573 |                         handler.postDelayed({ playNext() }, 1000)
 574 |                     }
 575 |                 }
 576 |             }
 577 |         } catch (e: Exception) { 
 578 |             DebugLogger.log("MEDIA_CRITICAL", "Failed to init MediaPlayer: ${e.message}")
 579 |             stopAllPlayback()
 580 |         }
 581 |     }
