 838 |     private fun handleHeadsetCommand() {
 839 |         val pm = getSystemService(Context.POWER_SERVICE) as PowerManager
 840 |         val isScreenOff = !pm.isInteractive
 841 |         
 842 |         DebugLogger.log("HEADSET_EVENT", "--- HEADSET CLICK DETECTED ---")
