 862 |     private var wakeRetryCount = 0
 863 |     private fun wakeDevice(pm: PowerManager) {
 864 |         DebugLogger.log("WAKE_TRACE", "Step 1: Entering wakeDevice() function")
 865 |         
 866 |         if (pm.isInteractive) {
 867 |             DebugLogger.log("WAKE_TRACE", "Step 1.1: Cancelled - Device is already interactive")
 868 |             return
 869 |         }
 870 | 
 871 |         try {
 872 |             // 1. Prepare Intent
 873 |             DebugLogger.log("WAKE_TRACE", "Step 2: Building WakeActivity Intent")
 874 |             val intent = Intent(this, WakeActivity::class.java).apply {
 875 |                 addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or 
 876 |                          Intent.FLAG_ACTIVITY_CLEAR_TOP or 
 877 |                          Intent.FLAG_ACTIVITY_SINGLE_TOP)
 878 |             }
 879 |             
 880 |             val pendingIntent = PendingIntent.getActivity(
 881 |                 this, 
 882 |                 999, 
 883 |                 intent, 
 884 |                 PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
 885 |             )
 886 |             DebugLogger.log("WAKE_TRACE", "Step 3: PendingIntent created (ID: 999)")
 887 | 
 888 |             // 2. Build High-Priority Notification
 889 |             val builder = NotificationCompat.Builder(this, "PlaybackChannel")
 890 |                 .setSmallIcon(android.R.drawable.ic_lock_power_off)
 891 |                 .setContentTitle("System Wake Request")
 892 |                 .setContentText("Click to restore visual interface")
 893 |                 .setPriority(NotificationCompat.PRIORITY_MAX)
 894 |                 .setCategory(NotificationCompat.CATEGORY_ALARM)
 895 |                 .setFullScreenIntent(pendingIntent, true)
 896 |                 .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
 897 |                 .setVibrate(longArrayOf(0L)) // Mute system vibration (0ms)
 898 |                 .setAutoCancel(true)
 899 |             DebugLogger.log("WAKE_TRACE", "Step 4: Notification Builder configured with FullScreenIntent")
 900 | 
 901 |             val nm = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
 902 |             
 903 |             // 3. Physical Hardware Wake - Using FULL_WAKE_LOCK for maximum power
 904 |             @Suppress("DEPRECATION")
 905 |             val wl = pm.newWakeLock(PowerManager.FULL_WAKE_LOCK or PowerManager.ACQUIRE_CAUSES_WAKEUP or PowerManager.ON_AFTER_RELEASE, "UniversalApp::EmergencyWake")
 906 |             
 907 |             DebugLogger.log("WAKE_TRACE", "Step 5: WakeLock created. Attempting acquire(10s)...")
 908 |             wl.acquire(10000L)
 909 |             DebugLogger.log("WAKE_TRACE", "Step 6: WakeLock ACQUIRED")
 910 | 
 911 |             // 4. Fire Notification
 912 |             DebugLogger.log("WAKE_TRACE", "Step 7: Dispatching Notification to NotificationManager")
 913 |             nm.notify(99, builder.build())
 914 |             
 915 |             // 5. Fire Activity Directly
 916 |             DebugLogger.log("WAKE_TRACE", "Step 8: Calling startActivity(WakeActivity)")
 917 |             startActivity(intent)
 918 |             DebugLogger.log("WAKE_TRACE", "Step 9: startActivity command sent")
 919 | 
 920 |             verifyPhysicalWake(pm, 0)
 921 |             
 922 |             handler.postDelayed({
 923 |                 DebugLogger.log("WAKE_TRACE", "Step 10: Cleaning up Wake Notification")
 924 |                 nm.cancel(99)
 925 |             }, 5000)
 926 | 
 927 |         } catch (e: Exception) {
 928 |             DebugLogger.log("WAKE_CRITICAL", "CRASH in wake sequence: ${e.message}")
 929 |             e.printStackTrace()
 930 |         }
 931 |     }
