 933 |     private fun verifyPhysicalWake(pm: PowerManager, checkCount: Int) {
 934 |         handler.postDelayed({
 935 |             val logicallyOn = pm.isInteractive
 936 |             DebugLogger.log("WAKE_VERIFY", "Check #$checkCount: Interactive=$logicallyOn")
 937 | 
 938 |             if (logicallyOn) {
 939 |                 wakeRetryCount = 0
 940 |                 // Service stays silent; we wait for WakeActivity.onWindowFocusChanged
 941 |                 DebugLogger.log("WAKE_VERIFY", "Logical wake confirmed. Waiting for Activity Focus signal.")
 942 |             } else if (checkCount < 8) { // Increased checks for slower devices
 943 |                 verifyPhysicalWake(pm, checkCount + 1)
 944 |             } else {
 945 |                 if (wakeRetryCount < 2) {
 946 |                     wakeRetryCount++
 947 |                     DebugLogger.log("WAKE_RECOVER", "Retrying wake sequence...")
 948 |                     speakStatus("Retry wake", 2)
 949 |                     wakeDevice(pm)
 950 |                 } else {
 951 |                     speakStatus("Wake failed. Check battery optimization.", 2)
 952 |                     wakeRetryCount = 0
 953 |                 }
 954 |             }
 955 |         }, 500)
 956 |     }
