 583 |     private fun pauseAudio() {
 584 |         val list = playlists[currentType]
 585 |         if (list.isNullOrEmpty()) {
 586 |             speakStatus("No solutions loaded to play.", 2)
 587 |             return
 588 |         }
 589 |         
 590 |         if (mediaPlayer?.isPlaying == true) {
 591 |             mediaPlayer?.pause()
 592 |             speakStatus("Paused", 2)
 593 |             updateMediaSessionState(false)
 594 |         } else {
 595 |             speakStatus("Resumed", 2)
 596 |             if (mediaPlayer == null) {
 597 |                 // Reconstruction: The player was released or never started
 598 |                 playCurrent()
 599 |             } else {
 600 |                 mediaPlayer?.start()
 601 |                 updateMediaSessionState(true)
 602 |             }
 603 |         }
 604 |     }
