 746 |     private var isClaiming = false
 747 |     private fun claimMediaFocus() {
 748 |         val now = System.currentTimeMillis()
 749 |         // Cooldown: Stop the OS focus-war loop (5-second minimum gap)
 750 |         if (isFocusHeld || isClaiming || (now - lastFocusLossTime < 5000)) return
 751 |         isClaiming = true
 752 | 
 753 |         val am = getSystemService(Context.AUDIO_SERVICE) as android.media.AudioManager
 754 |         
 755 |         if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
 756 |             val focusRequest = android.media.AudioFocusRequest.Builder(android.media.AudioManager.AUDIOFOCUS_GAIN)
 757 |                 .setAudioAttributes(android.media.AudioAttributes.Builder()
 758 |                     .setUsage(android.media.AudioAttributes.USAGE_MEDIA)
 759 |                     .setContentType(android.media.AudioAttributes.CONTENT_TYPE_MUSIC)
 760 |                     .build())
 761 |                 .setOnAudioFocusChangeListener { focusChange ->
 762 |                     when (focusChange) {
 763 |                         android.media.AudioManager.AUDIOFOCUS_LOSS,
 764 |                         android.media.AudioManager.AUDIOFOCUS_LOSS_TRANSIENT -> {
 765 |                             isFocusHeld = false
 766 |                             lastFocusLossTime = System.currentTimeMillis()
 767 |                             DebugLogger.log("SESSION", "Focus Surrendered")
 768 |                             handler.postDelayed({ isClaiming = false }, 5000)
 769 |                         }
 770 |                         android.media.AudioManager.AUDIOFOCUS_GAIN -> {
 771 |                             isFocusHeld = true
 772 |                             DebugLogger.log("SESSION", "Focus Re-Gained")
 773 |                         }
 774 |                     }
 775 |                 }
 776 |                 .build()
 777 |             
 778 |             val result = am.requestAudioFocus(focusRequest)
 779 |             if (result == android.media.AudioManager.AUDIOFOCUS_REQUEST_GRANTED) {
 780 |                 isFocusHeld = true
 781 |                 isClaiming = false
 782 |                 DebugLogger.log("SESSION", "Focus Secured")
 783 |                 mediaSession?.isActive = true
 784 |                 startSilentLoop()
 785 |             } else {
 786 |                 isClaiming = false
 787 |                 lastFocusLossTime = System.currentTimeMillis()
 788 |             }
 789 |         } else {
 790 |             isClaiming = false
 791 |         }
 792 |     }
