 856 |     private var wakeRetryCount = 0
 857 |     private fun wakeDevice(pm: PowerManager) {
 858 |         DebugLogger.log("WAKE_TRACE", "Step 1: Entering wakeDevice() function")
 859 |         
 860 |         if (pm.isInteractive) {
 861 |             DebugLogger.log("WAKE_TRACE", "Step 1.1: Cancelled - Device is already interactive")
 862 |             return
 863 |         }
 864 | 
 865 |         try {
 866 |             // 1. Prepare Intent
 867 |             DebugLogger.log("WAKE_TRACE", "Step 2: Building WakeActivity Intent")
 868 |             val intent = Intent(this, WakeActivity::class.java).apply {
 869 |                 addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or 
 870 |                          Intent.FLAG_ACTIVITY_CLEAR_TOP or 
 871 |                          Intent.FLAG_ACTIVITY_SINGLE_TOP)
 872 |             }
 873 |             
 874 |             val pendingIntent = PendingIntent.getActivity(
 875 |                 this, 
 876 |                 999, 
 877 |                 intent, 
 878 |                 PendingIntent.FLAG_UPDATE_CURRENT or PendingIntent.FLAG_IMMUTABLE
 879 |             )
 880 |             DebugLogger.log("WAKE_TRACE", "Step 3: PendingIntent created (ID: 999)")
 881 | 
 882 |             // 2. Build High-Priority Notification
 883 |             val builder = NotificationCompat.Builder(this, "PlaybackChannel")
 884 |                 .setSmallIcon(android.R.drawable.ic_lock_power_off)
 885 |                 .setContentTitle("System Wake Request")
 886 |                 .setContentText("Click to restore visual interface")
 887 |                 .setPriority(NotificationCompat.PRIORITY_MAX)
 888 |                 .setCategory(NotificationCompat.CATEGORY_ALARM)
 889 |                 .setFullScreenIntent(pendingIntent, true)
 890 |                 .setVisibility(NotificationCompat.VISIBILITY_PUBLIC)
 891 |                 .setVibrate(longArrayOf(0L)) // Mute system vibration (0ms)
 892 |                 .setAutoCancel(true)
 893 |             DebugLogger.log("WAKE_TRACE", "Step 4: Notification Builder configured with FullScreenIntent")
 894 | 
 895 |             val nm = getSystemService(Context.NOTIFICATION_SERVICE) as NotificationManager
 896 |             
 897 |             // 3. Physical Hardware Wake - Using FULL_WAKE_LOCK for maximum power
 898 |             @Suppress("DEPRECATION")
 899 |             val wl = pm.newWakeLock(PowerManager.FULL_WAKE_LOCK or PowerManager.ACQUIRE_CAUSES_WAKEUP or PowerManager.ON_AFTER_RELEASE, "UniversalApp::EmergencyWake")
 900 |             
 901 |             DebugLogger.log("WAKE_TRACE", "Step 5: WakeLock created. Attempting acquire(10s)...")
 902 |             wl.acquire(10000L)
 903 |             DebugLogger.log("WAKE_TRACE", "Step 6: WakeLock ACQUIRED")
 904 | 
 905 |             // 4. Fire Notification
 906 |             DebugLogger.log("WAKE_TRACE", "Step 7: Dispatching Notification to NotificationManager")
 907 |             nm.notify(99, builder.build())
 908 |             
 909 |             // 5. Fire Activity Directly
 910 |             DebugLogger.log("WAKE_TRACE", "Step 8: Calling startActivity(WakeActivity)")
 911 |             startActivity(intent)
 912 |             DebugLogger.log("WAKE_TRACE", "Step 9: startActivity command sent")
 913 | 
 914 |             verifyPhysicalWake(pm, 0)
 915 |             
 916 |             handler.postDelayed({
 917 |                 DebugLogger.log("WAKE_TRACE", "Step 10: Cleaning up Wake Notification")
 918 |                 nm.cancel(99)
 919 |             }, 5000)
 920 | 
 921 |         } catch (e: Exception) {
 922 |             DebugLogger.log("WAKE_CRITICAL", "CRASH in wake sequence: ${e.message}")
 923 |             e.printStackTrace()
 924 |         }
 925 |     }
