 927 |     private fun verifyPhysicalWake(pm: PowerManager, checkCount: Int) {
 928 |         handler.postDelayed({
 929 |             val logicallyOn = pm.isInteractive
 930 |             DebugLogger.log("WAKE_VERIFY", "Check #$checkCount: Interactive=$logicallyOn")
 931 | 
 932 |             if (logicallyOn) {
 933 |                 wakeRetryCount = 0
 934 |                 // Service stays silent; we wait for WakeActivity.onWindowFocusChanged
 935 |                 DebugLogger.log("WAKE_VERIFY", "Logical wake confirmed. Waiting for Activity Focus signal.")
 936 |             } else if (checkCount < 8) { // Increased checks for slower devices
 937 |                 verifyPhysicalWake(pm, checkCount + 1)
 938 |             } else {
 939 |                 if (wakeRetryCount < 2) {
 940 |                     wakeRetryCount++
 941 |                     DebugLogger.log("WAKE_RECOVER", "Retrying wake sequence...")
 942 |                     speakStatus("Retry wake", 2)
 943 |                     wakeDevice(pm)
 944 |                 } else {
 945 |                     speakStatus("Wake failed. Check battery optimization.", 2)
 946 |                     wakeRetryCount = 0
 947 |                 }
 948 |             }
 949 |         }, 500)
 950 |     }
